dtsPropsFor.AssetCard:
/** 表示する支援アセット */
asset: { id: string; name: string; nameEn?: string; operator: string; region?: string; assetTypes: ("free-office" | "cloud-credit" | "funding" | "equity-investment" | "grant-subsidy" | "mentoring" | "talent-program" | "community" | "overseas" | "accelerator")[]; stages: ("idea" | "seed" | "early" | "growth" | "any")[]; equity: "none" | "optional" | "required"; application: { status: "open" | "upcoming" | "rolling" | "recurring" | "closed"; deadline?: string; opensAt?: string; window?: string; note?: string }; value?: string; eligibility?: string; summary: string; url: string; tags?: string[] };
/** 進捗トラッキングUI（保存セレクト）を表示するか。false ならサインイン誘導リンクになる */
canTrack: boolean;
/** 現在時刻。締切までの残日数表示に使う（クライアントのマウント後に渡す） */
now?: Date;
/** 進捗ステータス変更時のコールバック */
onUserStatusChange: (assetId: string, status: "not_started" | "interested" | "planned" | "applied" | "accepted" | "rejected" | "skipped") => void;
/** 保存処理中はセレクトを無効化する */
saving: boolean;
/** ユーザーごとの保存済み進捗状態 */
userState?: { assetId: string; status: "not_started" | "interested" | "planned" | "applied" | "accepted" | "rejected" | "skipped"; updatedAt: string };

dtsPropsFor.Directory:
/** 一覧表示する支援アセットの配列（締切順などで並ぶ） */
assets: { id: string; name: string; nameEn?: string; operator: string; region?: string; assetTypes: string[]; stages: string[]; equity: "none" | "optional" | "required"; application: { status: "open" | "upcoming" | "rolling" | "recurring" | "closed"; deadline?: string; opensAt?: string; window?: string; note?: string }; value?: string; eligibility?: string; summary: string; url: string; tags?: string[] }[];
/** ユーザーごとの保存済み進捗の初期値 */
initialStates: { assetId: string; status: "not_started" | "interested" | "planned" | "applied" | "accepted" | "rejected" | "skipped"; updatedAt: string }[];
/** ログイン中ユーザー（未ログインは null）。進捗保存UIの可否を切り替える */
user: { id: string; email: string } | null;

dtsPropsFor.AuthForm:
/** 初期エラーメッセージ（OAuthコールバック失敗時などに表示） */
initialErrorMessage?: string;
/** サインイン画面かサインアップ画面か */
mode: "signin" | "signup";
